import { Component, inject, input, signal, computed, effect } from '@angular/core';
import { CommonModule } from '@angular/common';
import { catchError, finalize, of } from 'rxjs';
import { toSignal, toObservable } from '@angular/core/rxjs-interop';
import { switchMap } from 'rxjs';

import { ButtonModule } from 'primeng/button';
import { TableModule } from 'primeng/table';
import { SkeletonModule } from 'primeng/skeleton';
import { InputGroupModule } from 'primeng/inputgroup';
import { InputGroupAddonModule } from 'primeng/inputgroupaddon';
import { TagModule } from 'primeng/tag';
import { ToolbarModule } from 'primeng/toolbar';
import { ConfirmPopupModule } from 'primeng/confirmpopup';
import { TooltipModule } from 'primeng/tooltip';
import { ConfirmationService } from 'primeng/api';
import { TranslatePipe } from '@ngx-translate/core';

import { AppDefinition, AppInvite, AppVersion } from '../../models/app-store.models';
import { AppInstallation, AppInstallationService } from '../../services/app-installation.service';
import { AppInviteService } from '../../services/app-invite.service';
import { AppVersionService } from '../../services/app-version.service';
import { AppInviteStatusBadgeComponent } from '../app-invite-status-badge/app-invite-status-badge.component';
import { AppStatusBadgeComponent } from '../app-status-badge/app-status-badge.component';
import { TimelineModule } from 'primeng/timeline';
import { isNullOrUndefined } from '../../../../shared/utils';

@Component({
  selector: 'app-developer-console',
  imports: [
    CommonModule,
    ButtonModule,
    TableModule,
    SkeletonModule,
    InputGroupModule,
    InputGroupAddonModule,
    TagModule,
    ToolbarModule,
    ConfirmPopupModule,
    TooltipModule,
    TimelineModule,
    AppInviteStatusBadgeComponent,
    AppStatusBadgeComponent,
    TranslatePipe,
  ],
  providers: [ConfirmationService],
  templateUrl: './app-developer-console.component.html',
})
export class AppDeveloperConsoleComponent {
  readonly app = input.required<AppDefinition>();

  private readonly appInstallationService = inject(AppInstallationService);
  private readonly appInviteService = inject(AppInviteService);
  private readonly appVersionService = inject(AppVersionService);
  private readonly confirmationService = inject(ConfirmationService);

  // Installers
  readonly installersLoading = signal(false);
  readonly installers = signal<AppInstallation[]>([]);
  private installersLoaded = false;

  // Invites
  readonly invitesLoading = signal(false);
  readonly invites = signal<AppInvite[]>([]);
  private invitesLoaded = false;
  readonly isGeneratingInvite = signal(false);

  // Copy feedback
  readonly clientIdCopied = signal(false);
  readonly copiedTokenId = signal<string | null>(null);

  // Derived stats
  readonly activeInstallCount = computed(
    () => this.installers().filter((i) => i.isEnabled).length,
  );

  readonly estimatedMonthlyRevenue = computed(() => {
    const fee = this.app().feeModel;
    if (!fee) return null;
    return fee.amount * this.activeInstallCount();
  });

  // Version history
  readonly versionsLoading = signal(false);
  readonly versions = toSignal(
    toObservable(this.app).pipe(
      switchMap((app) => {
        if (isNullOrUndefined(app)) return of([]);
        this.versionsLoading.set(true);
        return this.appVersionService.getVersions(app.id).pipe(
          catchError(() => of([] as AppVersion[])),
          finalize(() => this.versionsLoading.set(false)),
        );
      }),
    ),
    { initialValue: [] as AppVersion[] },
  );

  readonly expandedVersions = signal<Set<string>>(new Set());

  toggleVersionExpanded(id: string): void {
    this.expandedVersions.update((set) => {
      const next = new Set(set);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  }

  getVersionDiff(curr: AppVersion, prev: AppVersion): { field: string; before: string; after: string }[] {
    const changes: { field: string; before: string; after: string }[] = [];
    const check = (field: string, a: string | undefined, b: string | undefined) => {
      if ((a ?? '') !== (b ?? '')) changes.push({ field, before: a ?? '—', after: b ?? '—' });
    };
    const checkArr = (field: string, a: string[], b: string[]) => {
      if (JSON.stringify(a.slice().sort()) !== JSON.stringify(b.slice().sort()))
        changes.push({ field, before: a.join(', ') || '—', after: b.join(', ') || '—' });
    };
    check('Name', prev.name, curr.name);
    check('Short description', prev.shortDescription, curr.shortDescription);
    check('Description', prev.description, curr.description);
    check('Health check URL', prev.healthCheckUrl, curr.healthCheckUrl);
    check('Icon URL', prev.iconUrl, curr.iconUrl);
    check('Developer name', prev.developerName, curr.developerName);
    checkArr('Categories', prev.categories, curr.categories);
    checkArr('Tags', prev.tags, curr.tags);
    const prevPoints = (prev.integrationPoints ?? []).map((p) => p.screenId).sort().join(', ');
    const currPoints = (curr.integrationPoints ?? []).map((p) => p.screenId).sort().join(', ');
    if (prevPoints !== currPoints)
      changes.push({ field: 'Integration points', before: prevPoints || '—', after: currPoints || '—' });
    return changes;
  }

  private readonly _loadEffect = effect(() => {
    const appId = this.app().id;
    if (!this.installersLoaded) {
      this.installersLoaded = true;
      this.installersLoading.set(true);
      this.appInstallationService
        .getAppInstallations(appId)
        .pipe(catchError(() => of([])))
        .subscribe((r) => {
          this.installers.set(r);
          this.installersLoading.set(false);
        });
    }
    if (!this.invitesLoaded && this.app().visibility === 'unlisted') {
      this.invitesLoaded = true;
      this.invitesLoading.set(true);
      this.appInviteService
        .getInvites(appId)
        .pipe(catchError(() => of([])))
        .subscribe((r) => {
          this.invites.set(r);
          this.invitesLoading.set(false);
        });
    }
  });

  copyClientId(): void {
    const id = this.app().clientId;
    if (isNullOrUndefined(id)) return;
    void navigator.clipboard.writeText(id).then(() => {
      this.clientIdCopied.set(true);
      setTimeout(() => this.clientIdCopied.set(false), 2000);
    });
  }

  copyToken(invite: AppInvite): void {
    void navigator.clipboard.writeText(invite.token).then(() => {
      this.copiedTokenId.set(invite.id);
      setTimeout(() => this.copiedTokenId.set(null), 2000);
    });
  }

  generateInvite(): void {
    const appId = this.app().id;
    this.isGeneratingInvite.set(true);
    this.appInviteService
      .createInvite(appId)
      .pipe(catchError(() => of(null)))
      .subscribe((invite) => {
        if (invite) {
          this.invites.update((prev) => [invite, ...prev]);
        }
        this.isGeneratingInvite.set(false);
      });
  }

  confirmRevokeInvite(event: Event, invite: AppInvite): void {
    this.confirmationService.confirm({
      target: event.target as EventTarget,
      message: 'Revoke this invite link? This cannot be undone.',
      icon: 'pi pi-exclamation-triangle',
      acceptLabel: 'Revoke',
      rejectLabel: 'Cancel',
      accept: () => this.revokeInvite(invite),
    });
  }

  private revokeInvite(invite: AppInvite): void {
    const appId = this.app().id;
    this.appInviteService
      .revokeInvite(appId, invite.id)
      .pipe(catchError(() => of(null)))
      .subscribe((updated) => {
        if (updated) {
          this.invites.update((prev) =>
            prev.map((i) => (i.id === updated.id ? updated : i)),
          );
        }
      });
  }
}
