import { ActivatedRoute, Router, RouterModule } from '@angular/router';
import {
  AppDefinition,
  AppReview,
  AppSubmissionReview,
} from '../../models/app-store.models';
import {
  AppSubmissionReviewRequest,
  VersionBumpType,
} from '../../models/api/app-store-api.models';
import { CommonModule, Location } from '@angular/common';
import { Component, DestroyRef, computed, effect, inject, signal } from '@angular/core';
import { FormsModule, Validators } from '@angular/forms';
import { catchError, map, of, switchMap, tap } from 'rxjs';
import {
  createDropdownField,
  createTextAreaField,
} from '../../../../shared/models/form-field.model';
import { isDefined, isNullOrUndefined } from '../../../../shared/utils';
import { toObservable, toSignal } from '@angular/core/rxjs-interop';

import { AccordionModule } from 'primeng/accordion';
import { AppDeveloperConsoleComponent } from '../../components/app-developer-console/app-developer-console.component';
import { AppInstallFacadeService } from '../../services/app-install-facade.service';
import { AppRatingDisplayComponent } from '../../components/app-rating-display/app-rating-display.component';
import { AppStatusBadgeComponent } from '../../components/app-status-badge/app-status-badge.component';
import { AppStoreService } from '../../services/app-store.service';
import { AppVersionService } from '../../services/app-version.service';
import { AppVisibilityBadgeComponent } from '../../components/app-visibility-badge/app-visibility-badge.component';
import { AuthDataService } from '../../../../core/services/auth-data.service';
import { BroadcastEventMessageService } from '../../../administration/services/broadcast-event-messages.service';
import { ButtonModule } from 'primeng/button';
import { CardModule } from 'primeng/card';
import { ClientDataService } from '../../../clients/services/client-data.service';
import { ConfirmDialogModule } from 'primeng/confirmdialog';
import { ConfirmationService } from 'primeng/api';
import { DEFAULT_SYSTEM_ID } from '../../../../core/models';
import { DialogModule } from 'primeng/dialog';
import { IdName } from '../../../../api';
import { ImgFallbackDirective } from '../../../../shared/directives/img-fallback.directive';
import { InputTextModule } from 'primeng/inputtext';
import { ModalFormService } from '../../../../shared/services/forms/modal-form.service';
import { ModalListFormComponent } from '../../../../shared/components/forms/modal-list-form/modal-list-form.component';
import { ProgressSpinnerModule } from 'primeng/progressspinner';
import { RatingModule } from 'primeng/rating';
import { ReviewService } from '../../services/review.service';
import { TabsModule } from 'primeng/tabs';
import { TextareaModule } from 'primeng/textarea';
import { ToggleSwitchModule } from 'primeng/toggleswitch';
import { TooltipModule } from 'primeng/tooltip';
import { TranslateService } from '@ngx-translate/core';
import { getFeeLabel } from '../../utils/fee.utils';

@Component({
  selector: 'app-detail',
  imports: [
    CommonModule,
    RouterModule,
    FormsModule,
    ButtonModule,
    RatingModule,
    DialogModule,
    ConfirmDialogModule,
    InputTextModule,
    TextareaModule,
    TooltipModule,
    AccordionModule,
    CardModule,
    ProgressSpinnerModule,
    ToggleSwitchModule,
    TabsModule,
    AppStatusBadgeComponent,
    AppVisibilityBadgeComponent,
    AppRatingDisplayComponent,
    ImgFallbackDirective,
    AppDeveloperConsoleComponent,
  ],
  providers: [ConfirmationService],
  templateUrl: './app-detail.component.html',
  styleUrls: ['./app-detail.component.scss'],
})
export class AppDetailComponent {
  private readonly route = inject(ActivatedRoute);
  private readonly router = inject(Router);
  private readonly location = inject(Location);
  private readonly appStoreService = inject(AppStoreService);
  private readonly reviewService = inject(ReviewService);
  private readonly installFacade = inject(AppInstallFacadeService);
  private readonly authDataService = inject(AuthDataService);
  private readonly clientDataService = inject(ClientDataService);
  private readonly modalFormService = inject(ModalFormService);
  private readonly appVersionService = inject(AppVersionService);
  private readonly translateService = inject(TranslateService);
  private readonly destroyRef = inject(DestroyRef);
  private readonly broadcastService = inject(BroadcastEventMessageService);

  // Identity - Reactive signals that update when auth state changes
  readonly currentUserId = computed(
    () => this.authDataService.getUserProfileSignal()()?.id ?? null,
  );
  readonly isAdmin = computed(
    () =>
      this.authDataService
        .getUserProfileSignal()()
        ?.roles?.some((role: IdName) => role.id === DEFAULT_SYSTEM_ID) ?? false,
  );
  readonly isDeveloper = computed(() => this.app()?.developerId === this.currentUserId());

  // Tab state (developer-only)
  readonly activeTab = signal<'overview' | 'developer-console'>('overview');

  onTabChange(tab: 'overview' | 'developer-console'): void {
    this.activeTab.set(tab);
  }

  // App Data (Signal-based)
  private readonly appId = toSignal(
    this.route.paramMap.pipe(map((params) => params.get('id'))),
  );

  readonly isLoading = signal(true);
  readonly error = signal<string | null>(null);

  // Refresh trigger for app data (similar to reviews)
  private readonly refreshAppTrigger = signal(0);

  private readonly appData = toSignal(
    toObservable(
      computed(() => ({
        id: this.appId(),
        trigger: this.refreshAppTrigger(),
      })),
    ).pipe(
      tap(() => this.isLoading.set(true)),
      switchMap(({ id }) => {
        if (isNullOrUndefined(id)) return of(null);
        return this.appStoreService
          .getAppById(id, this.clientDataService.getSelectedClient()?.id ?? '')
          .pipe(
            tap(() => this.isLoading.set(false)),
            catchError((err) => {
              console.error('Error loading app:', err);
              this.error.set('Unable to load app details. Please try again.');
              this.isLoading.set(false);
              return of(null);
            }),
          );
      }),
    ),
    { initialValue: null as AppDefinition | null },
  );

  readonly app = computed(() => this.appData());

  // Review State
  private readonly refreshReviewsTrigger = signal(0);
  readonly reviews = toSignal(
    toObservable(
      computed(() => ({
        id: this.appId(),
        trigger: this.refreshReviewsTrigger(),
      })),
    ).pipe(
      switchMap(({ id }) => {
        if (isNullOrUndefined(id)) return of([]);
        return this.reviewService
          .getReviewsForApp(id)
          .pipe(catchError(() => of([])));
      }),
    ),
    { initialValue: [] as AppReview[] },
  );

  // Submission review (for changesRequested banner)
  readonly latestReview = toSignal(
    toObservable(this.app).pipe(
      switchMap((app) => {
        if (app?.version.pendingVersionStatus !== 'changesRequested')
          return of(null);
        return this.appStoreService.getSubmissionReviews(app.id).pipe(
          map((reviews) => reviews[0] ?? null),
          catchError(() => of(null)),
        );
      }),
    ),
    { initialValue: null as AppSubmissionReview | null },
  );

  isSubmittingReview = signal(false);
  reviewError = signal<string | null>(null);

  isSubmittingApproval = signal(false);
  approvalError = signal<string | null>(null);

  // Installation State — derived directly from app.installation (populated by the API when owner is provided)
  // Expose facade state for template bindings
  readonly isPerformingInstallationAction =
    this.installFacade.isPerformingAction;
  readonly installationError = this.installFacade.error;
  readonly isTogglingEnabled = this.installFacade.isTogglingEnabled;
  readonly toggleEnabledError = this.installFacade.toggleEnabledError;
  readonly estimateLoading = this.installFacade.estimateLoading;
  readonly estimate = this.installFacade.estimate;
  readonly estimateError = this.installFacade.estimateError;

  readonly isInstalled = computed(() => this.app()?.installation != null);
  readonly installationIsEnabled = computed(
    () => this.app()?.installation?.isEnabled ?? false,
  );

  readonly canInstall = computed(() => {
    const app = this.app();
    return app?.version.activeVersionId != null && !this.isInstalled();
  });

  readonly feeLabel = computed(() => getFeeLabel(this.app()?.feeModel ?? null, this.translateService));

  // Shareable install URL
  readonly installUrl = computed(() => {
    const id = this.app()?.id;
    if (isNullOrUndefined(id)) return null;
    return `${window.location.origin}/#/app-store/${id}`;
  });

  readonly urlCopied = signal(false);

  copyInstallUrl(): void {
    const url = this.installUrl();
    if (isNullOrUndefined(url)) return;
    void navigator.clipboard.writeText(url).then(() => {
      this.urlCopied.set(true);
      setTimeout(() => this.urlCopied.set(false), 2000);
    });
  }

  readonly grantedPermissions = computed((): string[] => {
    const perms = this.app()?.installation?.grantedPermissions;
    if (!perms) return [];
    return Object.entries(perms).flatMap(([resource, actions]) =>
      actions.map((action) => `${resource}:${action}`),
    );
  });

  private readonly _estimateEffect = effect(() => {
    const app = this.app();
    const clientId = this.clientDataService.getSelectedClient()?.id;
    if (this.canInstall() && app?.feeModel != null && isDefined(clientId)) {
      this.installFacade.loadEstimate(app.id, clientId);
    }
  });

  // Review Form
  showReviewModal = signal(false);
  newReviewRating = signal(5);
  newReviewTitle = signal('');
  newReviewComment = signal('');

  openReviewModal() {
    this.showReviewModal.set(true);
  }

  closeReviewModal() {
    this.showReviewModal.set(false);
    this.resetReviewForm();
  }

  submitReview() {
    const id = this.appId();
    if (isNullOrUndefined(id)) return;

    const currentTitle = this.newReviewTitle().trim();
    const currentComment = this.newReviewComment().trim();
    const currentRating = this.newReviewRating();
    const profile = this.authDataService.getUserProfileSignal()();

    if (!currentTitle || !currentComment || currentRating < 1) {
      this.reviewError.set('Please provide a title, comment, and rating.');
      return;
    }

    // Construct complete user name from first and last name
    const firstName = profile?.['firstName'] as string | undefined;
    const lastName = profile?.['lastName'] as string | undefined;
    const fullName =
      [firstName, lastName].filter(Boolean).join(' ') || 'Anonymous';

    // Get organization from profile or fallback to Unknown
    const organization = profile?.['organizationName'] as string | undefined;
    const organizationName = organization?.trim() ?? 'Unknown';

    this.reviewError.set(null);
    this.isSubmittingReview.set(true);

    const clientId = this.clientDataService.getSelectedClient()?.id ?? '';
    this.reviewService
      .addReview(id, clientId, {
        userName: fullName,
        organizationName: organizationName,
        rating: currentRating,
        title: currentTitle,
        comment: currentComment,
      })
      .pipe(
        tap(() => {
          this.refreshReviewsTrigger.update((n) => n + 1);
          this.closeReviewModal();
        }),
        catchError((err) => {
          console.error('Review submission error:', err);
          this.reviewError.set(
            'Could not submit your review. Please try again.',
          );
          return of(null);
        }),
      )
      .subscribe({
        complete: () => this.isSubmittingReview.set(false),
      });
  }

  resetReviewForm() {
    this.newReviewRating.set(5);
    this.newReviewTitle.set('');
    this.newReviewComment.set('');
  }

  private refreshAppData(): void {
    this.refreshAppTrigger.update((n) => n + 1);
  }

  isApproved = computed(() => this.app()?.version.activeVersionId != null);

  canEdit = computed(() => {
    const app = this.app();
    if (!app) return false;
    const isDeveloper = app.developerId === this.currentUserId();
    const noPendingReview =
      isNullOrUndefined(app.version.pendingVersionId) ||
      app.version.pendingVersionStatus === 'changesRequested';
    return isDeveloper && noPendingReview;
  });

  goBack(): void {
    this.location.back();
  }

  startEdit() {
    const app = this.app();
    if (!app) return;
    this.router
      .navigate(['/app-store/editor'], {
        queryParams: { appId: app.id },
        state: { appToEdit: app },
      })
      .catch(() => {});
  }

  isEditDisabled = computed(() => {
    const app = this.app();
    if (!app) return true;
    return !this.canEdit();
  });

  getEditDisabledReason = computed(() => {
    const app = this.app();
    if (!app) return '';
    if (app.version.pendingVersionStatus === 'pendingReview')
      return 'Editing is disabled while under review';
    if (app.state === 'suspended')
      return 'Editing is disabled for suspended apps';
    return 'You can only edit apps in this status';
  });

  isInPendingReview = computed(
    () => this.app()?.version.pendingVersionStatus === 'pendingReview',
  );

  openSubmissionReviewModal() {
    const app = this.app();
    if (!app) return;

    const dummyField = createTextAreaField('dummy', 'dummy', undefined);

    this.modalFormService
      .openListItemModal<Record<string, string>>({
        modalConfig: {
          modalComponent: ModalListFormComponent,
          modalTitle: 'Review App Submission',
          modalFields: [
            createDropdownField(
              'status',
              'Decision',
              [
                { label: 'Approve', value: 'approved' },
                { label: 'Reject', value: 'rejected' },
                { label: 'Suspend', value: 'suspended' },
                { label: 'Request Changes', value: 'changesRequested' },
              ],
              undefined,
              {
                validations: [
                  { name: 'required', validator: Validators.required },
                ],
              },
            ),
            createTextAreaField(
              'comments',
              'Comments to Developer',
              undefined,
              {
                placeholder: 'Explain the reason for this decision...',
                validations: [
                  { name: 'required', validator: Validators.required },
                ],
              },
            ),
            createTextAreaField('internalNotes', 'Internal Notes', undefined, {
              placeholder: 'Internal notes for the team...',
            }),
          ],
          onSubmit: (data, ref) => {
            const request: AppSubmissionReviewRequest = {
              id: app.id,
              developerId: app.developerId,
              status: data['status'] as AppSubmissionReviewRequest['status'],
              comments: data['comments'],
              internalNotes: data['internalNotes'],
            };

            this.approvalError.set(null);
            this.isSubmittingApproval.set(true);

            return new Promise((resolve) => {
              this.appStoreService.reviewApp(app.id, request).subscribe({
                next: () => {
                  this.refreshAppData();
                  this.isSubmittingApproval.set(false);
                  ref.close();
                  resolve(true);
                },
                error: (err) => {
                  console.error(err);
                  this.approvalError.set(
                    'Could not submit review. Please try again.',
                  );
                  this.isSubmittingApproval.set(false);
                  resolve(false);
                },
              });
            });
          },
        },
        itemData: {
          status: '',
          comments: '',
          internalNotes: '',
        },
        destroyRef: this.destroyRef,
        field: dummyField,
      })
      .subscribe();
  }

  openSubmitVersionDialog(): void {
    const app = this.app();
    if (!app) return;

    const isFirstSubmission = app.version.activeVersionId == null;
    const dummyField = createTextAreaField('dummy', 'dummy', undefined);

    const modalFields = [
      ...(isFirstSubmission
        ? []
        : [
            createDropdownField(
              'bumpType',
              'Version Bump',
              [
                { label: 'Patch — bug fixes, no new features', value: 'patch' },
                {
                  label: 'Minor — new features, backward compatible',
                  value: 'minor',
                },
                { label: 'Major — breaking changes', value: 'major' },
              ],
              undefined,
              {
                validations: [
                  { name: 'required', validator: Validators.required },
                ],
              },
            ),
          ]),
      createTextAreaField('changelog', 'Changelog', undefined, {
        placeholder: 'Describe what changed in this version...',
        validations: [{ name: 'required', validator: Validators.required }],
      }),
    ];

    this.modalFormService
      .openListItemModal<{ bumpType: string; changelog: string }>({
        modalConfig: {
          modalComponent: ModalListFormComponent,
          modalTitle: 'Submit New Version',
          modalFields,
          onSubmit: (data, ref) =>
            new Promise((resolve) => {
              this.appVersionService
                .submitVersion(app.id, {
                  bumpType: isFirstSubmission
                    ? 'patch'
                    : (data['bumpType'] as VersionBumpType),
                  changelog: data['changelog'],
                })
                .subscribe({
                  next: () => {
                    this.refreshAppData();
                    ref.close();
                    resolve(true);
                  },
                  error: () => resolve(false),
                });
            }),
        },
        itemData: { bumpType: '', changelog: '' },
        destroyRef: this.destroyRef,
        field: dummyField,
      })
      .subscribe();
  }

  installApp(): void {
    const app = this.app();
    if (!app || !this.canInstall()) return;
    this.installFacade.installApp(app, this.destroyRef, () => {
      this.refreshAppData();
    });
  }

  uninstallApp(): void {
    const app = this.app();
    const installationId = app?.installation?.id;
    if (isNullOrUndefined(installationId)) return;

    const isExternalApp =
      app?.integrationPoints?.some((p) => p.screenId === 'appSidebar') ?? false;

    this.installFacade.uninstallApp(installationId, isExternalApp, () => {
      this.refreshAppData();
    });
  }

  flattenPermissions(perms: Record<string, string[]>): string[] {
    return Object.entries(perms).flatMap(([resource, actions]) =>
      actions.map((action) => `${resource}:${action}`),
    );
  }

  formatScreenId(screenId: string): string {
    return screenId.replace(/([A-Z])/g, ' $1').replace(/^./, (s) => s.toUpperCase()).trim();
  }

  toggleEnabled(): void {
    const installation = this.app()?.installation;
    if (isNullOrUndefined(installation)) return;

    this.installFacade.toggleEnabled(
      installation.id,
      installation.isEnabled,
      () => {
        this.refreshAppData();
      },
    );
  }
}
